const secret = $input.first().headers['x-n8n-secret'];
if (secret !== $env.N8N_WEBHOOK_SECRET) throw new Error('Unauthorized');
return $input.all();

const session = $('Fetch Session').first().json[0];
const steps   = $('Fetch Steps').all().map(s => s.json);
const event   = $('Validate Secret').first().json.body.event;

if (!session || !session.employee?.wa_number) return [];

const emp  = session.employee;
const org  = session.org?.name ?? 'your company';
const name = emp.full_name.split(' ')[0];

const messages = [];

if (event === 'onboarding_started') {
  let stepsText = steps.slice(0, 5).map((s, i) => `  ${i + 1}. ${s.title}`).join('\n');
  messages.push({ json: {
    to: emp.wa_number,
    message: `🎉 *Welcome to ${org}, ${name}!*\n\nI'm HRBot — your AI HR assistant. I'll guide you through your onboarding.\n\n📋 *Your onboarding checklist:*\n${stepsText}${steps.length > 5 ? `\n  ...and ${steps.length - 5} more` : ''}\n\nLet's get started! Reply with anything to begin. 👋`
  }});
} else if (event === 'step_completed') {
  const stepName    = $('Validate Secret').first().json.body.step_name;
  const nextStep    = $('Validate Secret').first().json.body.next_step;
  const totalSteps  = $('Validate Secret').first().json.body.total_steps;
  const doneCount   = $('Validate Secret').first().json.body.done_count;
  const pct = Math.round(doneCount / totalSteps * 100);
  messages.push({ json: {
    to: emp.wa_number,
    message: `✅ *Step completed:* ${stepName}\n\n📊 Progress: ${doneCount}/${totalSteps} (${pct}%)\n\n${nextStep ? `*Next:* ${nextStep}` : '🎊 All steps complete! Welcome aboard!'}`
  }});
} else if (event === 'onboarding_complete') {
  messages.push({ json: {
    to: emp.wa_number,
    message: `🎊 *Onboarding Complete!*\n\nWelcome aboard, ${name}!\n🆔 Employee ID: *${emp.employee_id ?? 'Pending'}*\n🏢 Department: *${emp.department ?? 'TBD'}*\n\nYou can now use HRBot for:\n• ✅ Tasks management\n• 📅 Leave applications\n• ⏰ Attendance tracking\n\nType *help* anytime to see what I can do! 🤖`
  }});
}

return messages;
